def solve():
    import sys
    input = sys.stdin.read
    data = input().split()

    idx = 0
    t = int(data[idx])
    idx += 1
    results = []

    for _ in range(t):
        n = int(data[idx])
        idx += 1
        a = data[idx]
        idx += 1
        b = data[idx]
        idx += 1

        if a == b:
            results.append(0)
            continue

        cnt_a = a.count('1')
        cnt_b = b.count('1')

        if cnt_a == 0:
            results.append(-1)
            continue

        if cnt_a == cnt_b:
            flip = False
            possible = True
            for i in range(n):
                expected = b[i]
                if flip:
                    current = '1' if a[i] == '0' else '0'
                else:
                    current = a[i]
                if current != expected:
                    if current == '1':
                        flip = not flip
                    else:
                        possible = False
                        break
            if possible:
                results.append(flip)
            else:
                results.append(-1)
        elif cnt_a == cnt_b + 1:
            flip = False
            possible = True
            for i in range(n):
                expected = b[i]
                if flip:
                    current = '1' if a[i] == '0' else '0'
                else:
                    current = a[i]
                if current != expected:
                    if current == '1':
                        flip = not flip
                    else:
                        possible = False
                        break
            if possible:
                results.append(flip + 1)
            else:
                results.append(-1)
        elif cnt_a == cnt_b - 1:
            flip = False
            possible = True
            for i in range(n):
                expected = b[i]
                if flip:
                    current = '1' if a[i] == '0' else '0'
                else:
                    current = a[i]
                if current != expected:
                    if current == '1':
                        flip = not flip
                    else:
                        possible = False
                        break
            if possible:
                results.append(flip + 1)
            else:
                results.append(-1)
        else:
            results.append(-1)

    for res in results:
        print(res)

if __name__ == "__main__":
    solve()
